async (params, browser) => {
  // Open Notion
  await browser.open('https://www.notion.so')

  // Let Notion load
  await browser.wait(3000)

  // Search via Notion internal API
  const result = await browser.evaluate(`const resp = await fetch('/api/v3/search', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ query: params.query, type: 'BlocksInSpace', limit: 20, filters: { isDeletedOnly: false, navigableBlockContentOnly: true } }) }); if (!resp.ok) throw new Error('Notion search failed: ' + resp.status); const data = await resp.json(); const results = (data.results || []).map(r => { const block = data.recordMap?.block?.[r.id]?.value; return { id: r.id, title: block?.properties?.title?.flat()?.join('') || r.highlight?.text || '', type: block?.type || '', last_edited: block?.last_edited_time ? new Date(block.last_edited_time).toISOString() : '', url: 'https://www.notion.so/' + r.id.replace(/-/g, '') }; }); return { result_count: results.length, total: data.total || results.length, results: results }`)

  return result
}
